# Check for processes locking files in the build directory\nGet-Process | ForEach-Object {\n    $process = $_\n    try {\n        $process.Modules | ForEach-Object {\n            if ($_.FileName -like \"C:\\Users\\rowdy\\AndroidStudioProjects\\ROSTRY\\app\\build*\") {\n                Write-Host \"Process: $($process.ProcessName) (ID: $($process.Id)) is using: $($_.FileName)\"\n            }\n        }\n    } catch {\n        # Ignore access denied errors\n    }\n}\n\n# Check for handles to files in the build directory using handle.exe from Sysinternals\n# Download from https://docs.microsoft.com/en-us/sysinternals/downloads/handle if not available\nif (Get-Command \"handle.exe\" -ErrorAction SilentlyContinue) {\n    handle.exe \"C:\\Users\\rowdy\\AndroidStudioProjects\\ROSTRY\\app\\build\"\n} else {\n    Write-Host \"handle.exe not found. Please download it from https://docs.microsoft.com/en-us/sysinternals/downloads/handle\"\n    Write-Host \"Alternatively, try closing Android Studio and any terminals that might be using the project directory\"\n}